<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <div 
                                v-for="(item, index) in reports" 
                                :key="loadKey + '_' + index" 
                                class="report-wrapper" 
                                style="margin-bottom: 20px; border: 1px solid #ddd; border-radius: 4px; overflow: hidden;">
                                <ReportViewer
                                    :viewerId="'viewer_' + loadKey + '_' + index"
                                    :parameter="item.parameter"
                                    :reportPath="item.reportPath">
                                </ReportViewer>
                            </div>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>
<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            reports: [],
            isLoading: false,
            reportPath: null,
            parameter: [],
            ClientData: [],
            LocationId: 0,
            loadKey: 0,  // Track unique load for keys/IDs
            FormSchema: [{
                layoutType: "triple",
                Data: [{
                    astype: "SelectField",
                    label: this.$t("ClientName"),
                    name: "Client",
                    value: "",
                    placeholder: this.$t('Select') + " " + this.$t('Client'),
                    mode: "tag",
                    config: {
                        options: [],
                        onChange: this.GetUtilityByClient
                    },
                    validationRules: {
                        "required": true
                    }
                },
                {
                    astype: "MultiSelectField",
                    label: this.$t("UtilityName"),
                    name: "Utilityname",
                    value: "",
                    placeholder: this.$t('Select') + " " + this.$t('Utilityname'),
                    mode: "tag",
                    config: {
                        options: [],
                    }
                }
                ]
            },
            ],
            buttons: [{
                type: "submit",
                class: "btn btn-success",
                text: "<i class='fa fa-search pr-2'></i>Search",
            },
            {
                type: "button",
                class: "btn btn-danger",
                text: "<i class='fa fa-close pr-2'></i>Clear all",
                onClick: this.ClearAll
            },
            ],
            DataLoaded: 0,
        };
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.GetClient();
    },
    methods: {
        ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            vm.FormSchema[0].Data[1].config.options = [];
            vm.reportPath = '';
            vm.parameter = [];
            vm.reports = [];
            vm.loadKey = 0;  // Reset loadKey on clear
            vm.$refs.BarcodeReport.validateForm.reset();
        },
        GetClient: async function () {
            var vm = this;
            vm.isLoading = true;
            var params = 'pageNumber=&pageSize=&Reqfrom=null&search=null&userId=null';
            DataServices.GetClient(params).then((response) => {
                if (response.data.length > 0) {
                    vm.ClientData = response.data;
                    //vm.ClientData = vm.convertApiTreeToFlatList(response.data);
                    vm.ClientData.forEach(element => {
                        var Obj = {
                            name: element.CHILD_NAME,
                            value: element.CHILD_USER_ID
                        }
                        vm.FormSchema[0].Data[0].config.options.push(Obj);
                    });
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
                vm.isLoading = false;
            });
        },
        convertApiTreeToFlatList(tree) {
            let flat = [];
            function walkParent(node) {
                flat.push({
                    CHILD_USER_ID: node.parenT_ID,
                    CHILD_NAME: node.parenT_NAME,
                    PARENT_ID: null
                });
                if (node.children && node.children.length > 0) {
                    node.children.forEach(child => {
                        flat.push({
                            CHILD_USER_ID: child.chilD_USER_ID,
                            CHILD_NAME: child.chilD_NAME,
                            PARENT_ID: node.parenT_ID
                        });
                    });
                }
            }
            tree.forEach(root => walkParent(root));
            return flat;
        },
        GetUtilityByClient: async function (x, y, z) {
            var vm = this;
            vm.FormSchema[0].Data[1].value = '';
            vm.FormSchema[0].Data[1].config.options = [];
            var ClientId = y.value;
            var url = `clientId=${ClientId}&configid=0&Reqfrom=&clientIds=`;
            await DataServices.GetUtilityByClient(url).then((response) => {
                if (response.data.length > 0) {
                    var UtilityData = response.data;
                    UtilityData.forEach(element => {
                        var Obj = {
                            name: element.UTILITY_NAME,
                            value: element.UTILITY_ID
                        }
                        vm.FormSchema[0].Data[1].config.options.push(Obj);
                    });
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        async onSubmit(e) {
            this.isLoading = true;
            this.loadKey = Date.now();  // Generate unique key for this load
            this.reports = [];  // Clear old reports (components will unmount)
            
            let commonParams = {
                ClientIds: e.Client,
                UtilityIds: e.Utilityname.length > 0
                    ? e.Utilityname.map(item => item.value).join(",")
                    : ''
            };
            try {
                // Wait for unmount to complete before pushing new reports
                await this.$nextTick();
                
                // Report 1
                let response1 = await DataServices.ReportMain(JSON.stringify({
                    reportName: "detailaccount",
                    ...commonParams
                }));
                this.reports.push({
                    reportPath: response1.data.reportpath,
                    parameter: response1.data.parameters
                    // Removed unused viewerId
                });
                // Report 2
                let response2 = await DataServices.ReportMain(JSON.stringify({
                    reportName: "detailaccountdivisionrate",
                    ...commonParams
                }));
                this.reports.push({
                    reportPath: response2.data.reportpath,
                    parameter: response2.data.parameters
                    // Removed unused viewerId
                });

                // Report 3
                let response3 = await DataServices.ReportMain(JSON.stringify({
                    reportName: "detailaccountsbareport",
                    ...commonParams
                }));
                this.reports.push({
                    reportPath: response3.data.reportpath,
                    parameter: response3.data.parameters
                    // Removed unused viewerId
                });
            } catch (error) {
                console.error("Error while loading reports:", error);
            } finally {
                this.isLoading = false;
            }
        }
    }
};
</script>

<style scoped>
.report-wrapper {
  margin-bottom: 20px;
}
.report-wrapper:last-child {
  margin-bottom: 0;
}
</style>